class Solution:
    def longestSubarray(self, nums):
        n = len(nums)
        def nondec(lo, hi):
            for t in range(lo + 1, hi + 1):
                if nums[t] < nums[t-1]:
                    return False
            return True
        best = 0
        for i in range(n):
            for j in range(i, n):
                ok = False
                for p in range(i, j + 1):
                    if not nondec(i, p - 1):
                        continue
                    if not nondec(p + 1, j):
                        continue
                    if p == i or p == j or nums[p-1] <= nums[p+1]:
                        ok = True
                        break
                if ok:
                    best = max(best, j - i + 1)
        return best

