class Solution:
    def longestSubarray(self, nums):
        n = len(nums)
        if n <= 2:
            return n
        left = [1] * n
        for i in range(1, n):
            if nums[i] >= nums[i-1]:
                left[i] = left[i-1] + 1
        right = [1] * n
        for i in range(n - 2, -1, -1):
            if nums[i] <= nums[i+1]:
                right[i] = right[i+1] + 1
        best = max(left)
        for i in range(n):
            # replace nums[i]: merge run ending at i-1 with run starting at i+1
            l = left[i-1] if i - 1 >= 0 else 0
            r = right[i+1] if i + 1 < n else 0
            if i - 1 >= 0 and i + 1 < n:
                if nums[i-1] <= nums[i+1]:
                    best = max(best, l + r + 1)
                else:
                    best = max(best, l + 1, r + 1)
            else:
                best = max(best, l + r + 1)
        return best

