var longestSubarray = function(nums) {
    const n = nums.length;
    if (n <= 2) return n;
    const left = new Array(n).fill(1);
    for (let i = 1; i < n; i++) if (nums[i] >= nums[i-1]) left[i] = left[i-1] + 1;
    const right = new Array(n).fill(1);
    for (let i = n - 2; i >= 0; i--) if (nums[i] <= nums[i+1]) right[i] = right[i+1] + 1;
    let best = 0;
    for (let i = 0; i < n; i++) if (left[i] > best) best = left[i];
    for (let i = 0; i < n; i++) {
        const l = i - 1 >= 0 ? left[i-1] : 0;
        const r = i + 1 < n ? right[i+1] : 0;
        if (i - 1 >= 0 && i + 1 < n) {
            if (nums[i-1] <= nums[i+1]) best = Math.max(best, l + r + 1);
            else best = Math.max(best, l + 1, r + 1);
        } else {
            best = Math.max(best, l + r + 1);
        }
    }
    return best;
};
